import{_ as a,o as t,c as r,a5 as o}from"./chunks/framework.DoqVi1lK.js";const m=JSON.parse('{"title":"Why Platform Mesh?","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/why-platform-mesh.md","filePath":"concepts/why-platform-mesh.md"}'),i={name:"concepts/why-platform-mesh.md"};function s(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="why-platform-mesh" tabindex="-1">Why Platform Mesh? <a class="header-anchor" href="#why-platform-mesh" aria-label="Permalink to &quot;Why Platform Mesh?&quot;">​</a></h1><p>Platform Mesh exists to make services discoverable, orderable, and manageable through a common declarative API model.</p><p>Traditional infrastructure often separates IaaS, PaaS, and SaaS into different layers, tools, and lifecycle models. Platform Mesh treats those service capabilities as declarative resources that can be offered by providers and consumed through a consistent Kubernetes Resource Model interface.</p><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Service consumers need to discover and order capabilities without learning every provider&#39;s runtime, tenant model, and operational interface.</p><p>Service providers need to expose a clear API contract without giving consumers direct access to implementation details or service runtimes.</p><p>Platform owners need a shared control plane for identity, authorization, account structure, service discovery, and lifecycle integration.</p><h2 id="approach" tabindex="-1">Approach <a class="header-anchor" href="#approach" aria-label="Permalink to &quot;Approach&quot;">​</a></h2><p>Platform Mesh separates the service management API from the actual service runtime.</p><ul><li>Providers publish declarative APIs for capabilities.</li><li>Consumers bind those APIs into isolated account workspaces.</li><li>Controllers reconcile requested resources into real services.</li><li>Identity and authorization mediate access across provider and consumer boundaries.</li></ul><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design principles&quot;">​</a></h2><p>Platform Mesh follows a declarative API model. APIs store desired state; controllers reconcile the real world toward that state.</p><p>It also favors decoupled components. A provider should be able to integrate with the mesh without becoming tightly coupled to every other platform component.</p><h2 id="managed-service-provider-pattern" tabindex="-1">Managed service provider pattern <a class="header-anchor" href="#managed-service-provider-pattern" aria-label="Permalink to &quot;Managed service provider pattern&quot;">​</a></h2><p>A managed service provider exposes a lifecycle API for a service capability and owns the automation that fulfills requests for that capability.</p><p>This separates:</p><ul><li>the management API that consumers use to order and manage capabilities</li><li>the provider runtime that implements the actual service</li></ul><p>The result is a consistent consumer experience while providers retain implementation and operational independence.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./architecture.html">Architecture</a></li><li><a href="./account-model.html">Account model</a></li><li><a href="./integration-paths.html">Integration paths</a></li><li><a href="./interaction-patterns/provider-to-consumer.html">Interaction patterns</a></li></ul>',20)])])}const u=a(i,[["render",s]]);export{m as __pageData,u as default};
